import type { Metadata } from "next";
import Link from "next/link";
import { notFound } from "next/navigation";
import { ArrowLeft, Mail, MapPin, Navigation, Phone } from "lucide-react";
import { getOfficeBySlug, offices } from "@/data/offices";

type OfficePageProps = {
  params: Promise<{ slug: string }>;
};

export function generateStaticParams() {
  return offices.map(({ slug }) => ({ slug }));
}

export async function generateMetadata({
  params,
}: OfficePageProps): Promise<Metadata> {
  const { slug } = await params;
  const office = getOfficeBySlug(slug);

  if (!office) {
    return {
      title: "Office Not Found | EduBh",
    };
  }

  return {
    title: office.city + " - " + office.officeName + " | EduBh",
    description:
      "Visit the EduBh " +
      office.officeName +
      " office in " +
      office.city +
      ". " +
      office.fullAddress,
  };
}

export default async function OfficeDetailsPage({ params }: OfficePageProps) {
  const { slug } = await params;
  const office = getOfficeBySlug(slug);

  if (!office) {
    notFound();
  }

  return (
    <div className="space-y-6">
      <section className="surface-card-strong relative overflow-hidden px-6 py-8 sm:px-8 sm:py-10">
        <div
          aria-hidden="true"
          className="absolute right-[-8%] top-[-40%] h-64 w-64 rounded-full bg-[radial-gradient(circle,rgba(124,58,237,0.18),transparent_68%)] blur-2xl"
        />
        <div className="relative space-y-5">
          <div className="eyebrow">
            <MapPin className="h-3.5 w-3.5" />
            <span>EduBh Office</span>
          </div>
          <div>
            <p className="text-sm font-semibold uppercase tracking-[0.2em] text-[var(--muted)]">
              {office.city}
            </p>
            <h1 className="section-title mt-2">{office.officeName}</h1>
            <p className="mt-4 max-w-3xl text-base leading-8 text-[var(--muted)]">
              Visit our {office.city} branch for program guidance, eligibility
              support, and admissions assistance.
            </p>
          </div>
        </div>
      </section>

      <div className="grid gap-6 lg:grid-cols-[minmax(0,1.08fr)_minmax(320px,0.92fr)]">
        <section className="surface-card-strong p-5 sm:p-6">
          <div className="flex items-start gap-4 rounded-[1.5rem] bg-white/88 p-5 shadow-[0_14px_28px_rgba(16,32,58,0.07)]">
            <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-purple-50 text-purple-600">
              <MapPin className="h-5 w-5" />
            </div>
            <div>
              <p className="text-[0.72rem] font-semibold uppercase tracking-[0.22em] text-[var(--muted)]">
                Complete Address
              </p>
              <address className="mt-3 not-italic text-base font-medium leading-8 text-[var(--foreground)]">
                {office.fullAddress}
              </address>
            </div>
          </div>

          <a
            href={office.googleMapsUrl}
            target="_blank"
            rel="noreferrer"
            className="button-primary mt-5 inline-flex w-full items-center justify-center gap-2 text-sm sm:w-auto"
          >
            <Navigation className="h-4 w-4" />
            Open in Google Maps
          </a>
        </section>

        <aside className="surface-card px-5 py-5 sm:px-6">
          <h2 className="text-[0.72rem] font-semibold uppercase tracking-[0.22em] text-[var(--muted)]">
            Contact Information
          </h2>
          <div className="mt-5 space-y-3">
            {office.phone && (
              <a
                href={"tel:" + office.phone.replaceAll(" ", "")}
                className="flex items-start gap-4 rounded-[1.4rem] bg-white/88 px-4 py-4 shadow-[0_12px_24px_rgba(16,32,58,0.06)] transition-transform hover:-translate-y-0.5"
              >
                <div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-2xl bg-[rgba(22,93,245,0.1)] text-[var(--brand)]">
                  <Phone className="h-4 w-4" />
                </div>
                <div>
                  <p className="font-semibold text-[var(--foreground)]">Phone</p>
                  <p className="mt-1 text-sm text-[var(--muted)]">
                    {office.phone}
                  </p>
                </div>
              </a>
            )}

            {office.email && (
              <a
                href={"mailto:" + office.email}
                className="flex items-start gap-4 rounded-[1.4rem] bg-white/88 px-4 py-4 shadow-[0_12px_24px_rgba(16,32,58,0.06)] transition-transform hover:-translate-y-0.5"
              >
                <div className="flex h-11 w-11 shrink-0 items-center justify-center rounded-2xl bg-[rgba(22,93,245,0.1)] text-[var(--brand)]">
                  <Mail className="h-4 w-4" />
                </div>
                <div className="min-w-0">
                  <p className="font-semibold text-[var(--foreground)]">Email</p>
                  <p className="mt-1 break-all text-sm text-[var(--muted)]">
                    {office.email}
                  </p>
                </div>
              </a>
            )}
          </div>
        </aside>
      </div>

      <Link
        href="/contact"
        className="button-secondary inline-flex items-center gap-2 text-sm"
      >
        <ArrowLeft className="h-4 w-4" />
        Back to Contact
      </Link>
    </div>
  );
}

